        const uint col_base = word_idx * 8;
        const uint grp = col_base / group_size;

        const uint32_t word0 = w32_r0[word_idx];
        const uint32_t word1 = w32_r1[word_idx];

        float nd0 = 0.0f, nd1 = 0.0f, gs = 0.0f;
        for (uint ni = 0; ni < 8; ni++) {
