fn decodeOneToken(
    comptime Config: type,
    device: *const metal.Device,
    pipelines: *const TransformerPipelines,
    args: *ForwardDecodeArgsT(Config.WeightBuffer),
    token_id: u32,
    position: u32,
    params: SamplingParams,
    scratch: []f32,
    indices: []u32,
    rng: std.Random,
) u32 {
    std.debug.assert(
        position < Config.max_context_length,
    );
    std.debug.assert(token_id < Config.vocab_size);
    std.debug.assert(args.flag_buf.value != null);

    args.token_id = token_id;
    args.position = position;

    const cmd = device.beginCommandBufferUnretained();
    const enc = device.beginCompute(cmd);
    forwardDecode(
        Config,
        device,
        enc,
        pipelines,
        args.*,
    );
    bufferBarrier(enc);
    dispatchCompletionFlag(
        device,
        enc,
        pipelines.set_completion_flag,
        args.flag_buf,
    );
    enc.msgSend(void, "endEncoding", .{});
    device.commitAndSpinOnFlag(cmd, args.flag_ptr);

    const logits = readLogitsSlice(
        args.logits,
        Config.vocab_size,
    );
    return sampleToken(
        logits,
        params,
        scratch,
        indices,
        rng,
    );
}

/// Check whether a token ID is in the EOS set.
pub fn isEosToken(
    token_id: u32,
    eos_ids: []const u32,
) bool {
    std.debug.assert(eos_ids.len > 0);
    for (eos_ids) |eos| {
        if (token_id == eos) return true;
    }

    pub fn commitAndSpinOnFlag(
        self: *const Device,
        cmd_buf: objc.Object,
        flag_ptr: *volatile u32,
    ) void {
        std.debug.assert(
            self.command_queue.value != null,
        );
        std.debug.assert(cmd_buf.value != null);
        // Flag must be 0 (reset) before commit.
        std.debug.assert(flag_ptr.* == 0);

        cmd_buf.msgSend(void, "commit", .{});

        // Spin until GPU sets flag to 1.
        // On Apple Silicon unified memory, GPU writes
        // are visible to CPU after cache coherency
        // propagation (~10-50 ns typical).
        while (flag_ptr.* == 0) {
            // Busy-wait — appropriate for sub-10 us
            // GPU work where kernel trap overhead
            // exceeds the wait time.
            std.atomic.spinLoopHint();
        }

        // Reset for next use.
        flag_ptr.* = 0;
    }

    /// Insert a buffer-scope memory barrier on the compute
    /// encoder. Required between dispatches that share buffers
    /// within the same encoder — ensures writes from the
    /// previous dispatch are visible to the next.
    pub fn memoryBarrier(
        self: *const Device,
        encoder: objc.Object,
    ) void {
        // Assert the device is in a valid state.
        std.debug.assert(self.command_queue.value != null);

        // MTLBarrierScopeBuffers = 1.
        encoder.msgSend(
            void,
            "memoryBarrierWithScope:",
            .{@as(c_ulong, 1)},
        );
    }
};

