    acc1 = simd_sum(acc1);

    if (lane == 0) {
        if (row0_valid) residual[row0] += bf16_round(acc0);
        if (row1_valid) residual[row1] += bf16_round(acc1);
    }
}

// ====================================================================
// Kernel 6: q4mv_spec_fused_pair_silu_f16io — gate/up + SiLU fused
// ====================================================================
/// Fused gate+up projection with SiLU activation and elementwise
/// multiply: output[row] = silu(gate_row) * up_row.  Eliminates
/// the separate SiLU+elementwise_mul dispatch and two barriers
/// per block.
///
/// Uses 1 row per simdgroup (not 2) to keep register pressure
/// low enough for max_threads >= 512 despite the extra exp()
/// in the SiLU output stage.
///

input.old_content:
float acc0 = 0.0f, acc1 = 0.0f;

// Interleaved access with per-word group accumulation.
#pragma clang loop unroll(disable)
for (uint w = 0; w < uint32s_per_lane; w++) {
    const uint word_idx = w * 32 + lane;
    const uint col_base = word_idx * 8;
    const uint grp = col_base / group_size;

    const uint32_t word0 = w32_r0[word_idx];
    const uint32_t word1 = w32_r1[word_idx];

    float nd0 = 0.0f, nd1 = 0.0f, gs = 0.0f;
    for (uint ni = 0; ni < 8; ni++) {
        const float x = float(tg_input[col_base + ni]);
        nd0 += float((word0 >> (ni * 4)) & 0xFu) * x;
        nd1 += float((word1 >> (ni * 4)) & 0xFu) * x;
        gs += x;
    }

    const uint sc0 =
        safe_row0 * groups_per_row + grp;
    const uint sc1 =
        safe_row1 * groups_per_row + grp;
    acc0 += bf16_to_f32(scales[sc0]) * nd0
          + bf16_to_f32(biases[sc0]) * gs;
    acc1 += bf16_to_f32(scales[sc1]) * nd1
          + bf16_to_f32(biases[sc1]) * gs;
}

input.new_content:
float acc0 = 0.0f, acc1 = 0.0f;

// Interleaved access, 2 words per iteration for ILP.
static_assert(uint32s_per_lane % 2 == 0,
    "uint32s_per_lane must be even for 2-word loop.");
#pragma clang loop unroll(disable)
for (uint w = 0; w < uint32s_per_lane; w += 2) {
    const uint wi_a = w * 32 + lane;
    const uint wi_b = (w + 1) * 32 + lane;
    const uint cb_a = wi_a * 8;
    const uint cb_b = wi_b * 8;

    // Issue all 4 weight reads upfront for ILP.
    const uint32_t wa0 = w32_r0[wi_a];
    const uint32_t wa1 = w32_r1[wi_a];
    const uint32_t wb0 = w32_r0[wi_b];
    const uint32_t wb1 = w32_r1[wi_b];

    // Word A.
    float nd0 = 0.0f, nd1 = 0.0f, gs = 0.0f;
    for (uint ni = 0; ni < 8; ni++) {
        const float x = float(tg_input[cb_a + ni]);
        nd0 += float((wa0 >> (ni * 4)) & 0xFu) * x;
        nd1 += float((wa1 >> (ni * 4)) & 0xFu) * x;
        gs += x;
    }
    const uint sca0 =
        safe_row0 * groups_per_row + cb_a / group_size;
    const uint sca1 =
        safe_row1 * groups_per_row + cb_a / group_size;
    acc0 += bf16_to_f32(scales[sca0]) * nd0
          + bf16_to_f32(biases[sca0]) * gs;
    acc1 += bf16_to_f32(scales[sca1]) * nd1
          + bf16_to_f32(biases[sca1]) * gs;

    // Word B.
    nd0 = 0.0f; nd1 = 0.0f; gs = 0.0f;
    for (uint ni = 0; ni < 8; ni++) {
        const float x = float(tg_input[cb_b + ni]);
        nd0 += float((wb0 >> (ni * 4)) & 0xFu) * x;
        nd1 += float((wb1 >> (ni * 4)) & 0xFu) * x;
        gs += x;
    }
    const uint scb0 =
        safe_row0 * groups_per_row + cb_b / group_size;
    const uint scb1 =
        safe_row1 * groups_per_row + cb_b / group_size;
    acc0 += bf16_to_f32(scales[scb0]) * nd0
          + bf16_to_f32(biases[scb0]) * gs;
    acc1 += bf16_to_f32(scales[scb1]) * nd1
          + bf16_to_f32(biases[scb1]) * gs;
}
